        YGNodeStyleSetMargin(root_child0, YGEdge.Bottom, 1);
        YGNodeStyleSetMargin(root_child0, YGEdge.Left, 12);
        YGNodeInsertChild(root, root_child0, 0);
        YGNodeCalculateLayout(root, float.NaN, float.NaN, YGDirection.LTR);
